local PathButtons = {} -- Tempat menyimpan instance eksternal button secara dinamis
local PathCooldowns = {} -- Melacak status cooldown setiap path
_G.CustomPathsEnabled = false

-- FUNGSI UNTUK MENGEKSEKUSI CFRAME PATH
local function playPath(pathName, pathData)
    local char = LocalPlayer.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp then return end
    
    for _, point in ipairs(pathData) do
        -- Jika toggle utama dimatikan (Off), pergerakan langsung dihentikan seketika
        if not _G.CustomPathsEnabled then 
            break 
        end
        
        if not hrp or not hrp.Parent then break end
        if point.cf then
            pcall(function()
                hrp.CFrame = CFrame.new(table.unpack(point.cf))
            end)
        end
        task_wait(point.dt or 0.016) 
    end
end

-- FUNGSI MEMPROSES KLIK DAN COOLDOWN 2 DETIK
local function triggerPath(pathName, btnWrapper)
    local pathTable = Paths[pathName]
    if not pathTable or #pathTable == 0 then 
        Library:Notify("Error", "Koordinat " .. pathName .. " masih kosong! Silakan copas data ke dalam script terlebih dahulu.", 3)
        return 
    end

    -- Pengecekan Cooldown
    local lastUsed = PathCooldowns[pathName] or 0
    if tick() - lastUsed < 2 then
        local rem = math.ceil(2 - (tick() - lastUsed))
        Library:Notify("Cooldown", pathName .. " sedang cooldown! Tunggu " .. rem .. " detik.", 1.5)
        return
    end

    PathCooldowns[pathName] = tick()

    -- Efek Visual Cooldown pada Tombol Melayang
    task_spawn(function()
        for i = 2, 1, -1 do
            if btnWrapper then
                pcall(function() btnWrapper:SetText("[" .. i .. "s] " .. pathName:upper()) end)
            end
            task_wait(1)
        end
        if btnWrapper then
            pcall(function() btnWrapper:SetText(pathName:upper()) end)
        end
    end)

    -- Jalankan Pergerakan
    task_spawn(function()
        playPath(pathName, pathTable)
    end)
end

